import{_ as t,o as a,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"105. Home Visit Safety","description":"","frontmatter":{"title":"105. Home Visit Safety","eba":"Allied Health Professionals 2021-2026","topics":["leave","family-violence-leave"]},"headers":[],"relativePath":"ebas/allied-health/ohs/105-home-visit-safety.md","filePath":"ebas/allied-health/ohs/105-home-visit-safety.md"}'),i={name:"ebas/allied-health/ohs/105-home-visit-safety.md"};function n(r,e,h,l,c,p){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_105-home-visit-safety" tabindex="-1">105. Home Visit Safety <a class="header-anchor" href="#_105-home-visit-safety" aria-label="Permalink to &quot;105. Home Visit Safety&quot;">​</a></h1><p><strong>105.1</strong> The Employer will ensure that where an Employee is undertaking a home visit:</p><p><strong>(a)</strong> the Employee has received training relevant to performing their work in that environment including Employee and client safety (such as family violence); and</p><p><strong>(b)</strong> the Employee has ready access to other Employee/s:</p><p><strong>(i)</strong> to report an emergency; and/or</p><p><strong>(ii)</strong> to receive clinical advice; and</p><p><strong>(c)</strong> where the home visit has concluded and the Employee has not confirmed their safety, the Employer will ensure that another employee/s contacts the Employee to confirm their safety.</p><p><strong>105.2</strong> Where a Grade/Level/Class 1 Employee is undertaking home visits the Employer will ensure that they have first completed the necessary training and orientation to ensure that they have the necessary skills, knowledge and experience to effectively and safely perform home visit duties and will receive the required ongoing support in accordance with subclause 105.1.</p><p><strong>105.3</strong> Where an Employee has concerns about their safety following the initial screening processes, or where an Employee has concerns about their safety as a result of their dealings with a client/customer/patient, the Employer will ensure that:</p><p><strong>(a)</strong> the safety issue / hazard is identified;</p><p><strong>(b)</strong> a risk assessment is undertaken in consultation with the Employee/s, the Employee’s HSR (where applicable) and where requested by the Employee/s, the Union and/or any other relevant employee/s;</p><p><strong>(c)</strong> subject to subclauses 105.4. and 105.5, an appropriate hazard / risk control is implemented; and</p><p><strong>(d)</strong> the control measures are evaluated and reviewed.</p><p><strong>105.4</strong> The objective of the process described at subclause 105.3 is to identify a hazard / risk control measure the Employee agrees addresses their safety concern. An Employee is entitled to dispute whether the hazard / risk control measure in subclause 105.3(c) addresses their safety concerns and is appropriate in accordance with the OHS Act.</p><p><strong>105.5</strong> At any time, if a safety issue involves an immediate threat to the Employee’s health or safety an Employer or Employee may, after consultation, direct that work cease in accordance with the OHS Act, save that, consistent with an Employee’s common law right, an Employee has the right to:</p><p><strong>(a)</strong> cease seeing an individual client / customer / patient or leave a location/environment at any time where they feel unsafe; and/ or</p><p><strong>(b)</strong> not perform work where they believe is a threat to their safety, including when they do not feel safe visiting an individual client/customer/patient or attending a location/environment.</p><p><strong>105.6</strong> Where a direction under subclause 105.5 occurs, the cease work would apply to visiting that individual client / customer / patient or location/environment where performing this work gives rise to an immediate threat to the Employee’s safety until resolved in accordance with the OHS Act, which includes having the matter determined by Worksafe and the right to appeal.</p><p><strong>105.7</strong> During any period for which work has ceased in accordance with a direction under subclause 105.5, the Employer may assign any Employees whose work is affected to suitable alternative work.</p><p><strong>105.8</strong> Nothing in this clause 105 limits the ability of any party to exercise any right under the OHS Act including to request an inspector attend the workplace to assist in the resolution of the health and safety issue, having the matter determined by Worksafe, any escalation process or right to appeal.</p><p><strong>105.9</strong> The requirements of this clause 105 applies to all situations where an Employee is away from the Employer’s premises with a client/s / customer/s / patient/s, family or carer/s.</p>',21)])])}const y=t(i,[["render",n]]);export{m as __pageData,y as default};
